mapper.select:
select i.inbound_id AS inboundId, i.inbound_request_date AS inboundRequestDate, i.inbound_status AS inboundStatus, i.inbound_amount AS inboundAmount, i.reject_reason_message AS rejectReasonMessage, p.product_name AS productName, b.business_id AS businessId from inbound_table i join product p on i.product_id = p.product_id join business_table b on p.business_id = b.business_id
i.inbound_status = #{status}
ORDER BY i.inbound_request_date DESC LIMIT #{limit} OFFSET #{offset}

