UPDATE stock_table
SET stock_amount = stock_amount + #{amount}
WHERE stock_id = #{stockId}

UPDATE inbound_table
SET
    inbound_status = '반려',
    reject_reason_message = #{rejectReasonMessage}
WHERE inbound_id = #{inboundId}

